import React, { useEffect, useState } from 'react';
import { 
  Box, 
  Container, 
  Typography, 
  Paper,
  CircularProgress,
  Alert
} from '@mui/material';
import { useAuth } from '../context/AuthContext';
import api from '../utils/api';

const Dashboard = () => {
  console.log("DASHBOARD RENDERING STARTED");

  const { currentUser, isAuthenticated } = useAuth();
  console.log("Auth state in Dashboard:", { isAuthenticated, currentUser });

  const [loading, setLoading] = useState(true);
  const [wallets, setWallets] = useState([]);
  const [transactions, setTransactions] = useState([]);
  const [error, setError] = useState(null);
  const [debug, setDebug] = useState({});

  // Simple fetch function - no caching
  useEffect(() => {
    console.log("Dashboard useEffect triggered", { isAuthenticated, userId: currentUser?.id });

    const fetchData = async () => {
      console.log("Starting data fetch...");
      setLoading(true);
      setError(null);

      try {
        console.log("Attempting to fetch user wallet");
        // Check if we have a user ID
        if (currentUser && currentUser.id) {
          try {
            console.log(`Fetching wallet for user ${currentUser.id}`);
            const walletsResponse = await api.get(`/wallet/${currentUser.id}`);
            console.log("Wallet response:", walletsResponse.data);

            // Convert to array if single object
            const walletData = Array.isArray(walletsResponse.data) 
              ? walletsResponse.data 
              : [walletsResponse.data];

            setWallets(walletData);
            console.log("Wallets set:", walletData);
          } catch (err) {
            console.error("Wallet fetch error:", err);
            setError(`Wallet error: ${err.message}`);
          }

          try {
            console.log(`Fetching transactions for user ${currentUser.id}`);
            const txResponse = await api.get(`/transaction/user/${currentUser.id}`);
            console.log("Transactions response:", txResponse.data);
            setTransactions(Array.isArray(txResponse.data) ? txResponse.data : []);
          } catch (err) {
            console.error("Transactions fetch error:", err);
            setError(`Transactions error: ${err.message}`);
          }
        } else {
          console.warn("No user ID available for data fetch");
          setError("No user ID found");
        }
      } catch (err) {
        console.error("General error:", err);
        setError(`Failed to load data: ${err.message}`);
      } finally {
        setLoading(false);
        console.log("Data fetch complete");
      }
    };

    if (isAuthenticated) {
      fetchData();
    } else {
      setLoading(false);
      console.log("Not authenticated, skipping data fetch");
    }
  }, [isAuthenticated, currentUser?.id]);

  // VERY SIMPLE RENDERING FOR DEBUGGING
  console.log("Before Dashboard render return");

  return (
    <Container maxWidth="lg" sx={{ mt: 4, mb: 4 }}>
      <Paper sx={{ p: 3, mb: 3, bgcolor: '#ffebee', border: '1px solid red' }}>
        <Typography variant="h6" color="error">Debug Panel</Typography>
        <Box component="pre" sx={{ maxHeight: 200, overflow: 'auto', fontSize: '0.8rem' }}>
          {JSON.stringify({
            isAuthenticated,
            currentUser,
            wallets: wallets.length,
            transactions: transactions.length,
            loading,
            error
          }, null, 2)}
        </Box>
      </Paper>

      {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}

      {loading ? (
        <Box display="flex" justifyContent="center" p={4}>
          <CircularProgress />
        </Box>
      ) : (
        <>
          <Typography variant="h4" gutterBottom>
            Dashboard
          </Typography>

          <Paper sx={{ p: 3, mb: 3 }}>
            <Typography variant="h5">
              User: {currentUser?.username || 'Unknown'}
            </Typography>
            <Typography>
              User ID: {currentUser?.id || 'Not available'}
            </Typography>
          </Paper>

          <Paper sx={{ p: 3, mb: 3 }}>
            <Typography variant="h5" gutterBottom>Wallet Information</Typography>
            {wallets.length === 0 ? (
              <Typography color="error">No wallet data found</Typography>
            ) : (
              wallets.map((wallet, index) => (
                <Box key={index} sx={{ mb: 2 }}>
                  <Typography>
                    Balance: {wallet.fiat_balance} {wallet.currency}
                  </Typography>
                </Box>
              ))
            )}
          </Paper>

          <Paper sx={{ p: 3 }}>
            <Typography variant="h5" gutterBottom>Recent Transactions</Typography>
            {transactions.length === 0 ? (
              <Typography color="error">No transaction data found</Typography>
            ) : (
              transactions.slice(0, 5).map((tx, index) => (
                <Box key={index} sx={{ mb: 1, p: 1, borderBottom: '1px solid #eee' }}>
                  <Typography>
                    {tx.sender_id === currentUser?.id ? 'Sent' : 'Received'}: {tx.source_amount} {tx.source_currency}
                  </Typography>
                  <Typography variant="caption">
                    Date: {new Date(tx.timestamp).toLocaleString()}
                  </Typography>
                </Box>
              ))
            )}
          </Paper>
        </>
      )}
    </Container>
  );
};

export default Dashboard;
